207		private selectRandomStylesFromCategories(
208			styles: { primary_category_id?: number; style_id: number }[],
209			categoryIds: number[],
210		): number[] {
211			return this.selectRandomStylesFromCategoriesGeneric(
212				styles,
213				categoryIds,
214				'primary_category_id',
215				'Category',
216			);
217		}
