219		private selectRandomStylesFromRootCategories(
220			styles: { root_category_id?: number; style_id: number }[],
221			categoryIds: number[],
222		): number[] {
223			return this.selectRandomStylesFromCategoriesGeneric(
224				styles,
225				categoryIds,
226				'root_category_id',
227				'Root category',
228			);
229		}
230	
231		private selectRandomStylesFromCategoriesGeneric<
232			T extends { style_id: number } & Partial<Record<K, number>>,
233			K extends string,
234		>(styles: T[], categoryIds: number[], categoryKey: K, categoryLabel: string): number[] {
235			if (categoryIds.length === 0) {
236				return [];
237			}
238	
239			const stylesByCategory: Record<number, T[]> = {};
240			for (const style of styles) {
241				const categoryId = style[categoryKey];
242				if (categoryId !== undefined) {
243					// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
244					stylesByCategory[categoryId] ??= [];
245					stylesByCategory[categoryId].push(style);
246				}
247			}
248	
249			const selectedStyles: number[] = [];
250	
251			const emptyCategoryIds: number[] = [];
252	
253			for (const categoryId of categoryIds) {
254				const categoryStyles = stylesByCategory[categoryId];
255				if (categoryStyles && categoryStyles.length > 0) {
256					const randomIndex = Math.floor(Math.random() * categoryStyles.length);
257					const styleId = categoryStyles[randomIndex]?.style_id;
258					if (styleId) {
259						selectedStyles.push(styleId);
260					}
261				} else {
262					emptyCategoryIds.push(categoryId);
263				}
264			}
265	
266			if (emptyCategoryIds.length > 0) {
267				this.logger.warn(`No styles found for ${categoryLabel.toLowerCase()}`, {
268					emptyCategoryIds,
269					totalCategories: categoryIds.length,
270				});
271			}
272	
273			this.logger.debug(`${categoryLabel} selection complete`, {
274				selectedCount: selectedStyles.length,
275				totalCategories: categoryIds.length,
276				emptyCategories: emptyCategoryIds.length,
277			});
278	
279			return selectedStyles;
280		}
