282		async getFrequentlyBoughtTogetherByRootCategories({
283			styleIds,
284			exclude = [],
285		}: FrequentlyBoughtTogetherRootCategoriesQueryDto): Promise<FrequentlyBoughtTogetherRootCategoriesResponseDto> {
286			let fallbackUsed = false;
287	
288			this.logger.log(
289				'[getFrequentlyBoughtTogetherByRootCategories] Starting root category FBT fetch',
290				{
291					styleIds,
292					excludeCount: exclude.length,
293				},
294			);
295	
296			try {
297				const styles = await Promise.all(
298					styleIds.map((id) => this.stylesService.getStyleById({ styleId: id })),
299				);
300	
301				const validStyles = styles.filter(Boolean) as IStyleBase[];
302				if (validStyles.length === 0) {
303					throw new BadRequestException(
304						`No styles found for styleIds: ${styleIds.join(', ')}`,
305					);
306				}
307	
308				const cartRootCategoryIds = validStyles
309					.map((_style) => _style.root_category_id)
310					.filter(Boolean) as number[];
311				let correlatedCategoryIds: number[] = [];
312	
313				for (const style of validStyles) {
314					if (style.root_category_id) {
315						const correlations =
316							await this.rootCategoriesCorrelationsService.getTopCorrelatedCategories({
317								rootCategoryId: style.root_category_id,
318								limit: 4,
319								exclude: cartRootCategoryIds,
320							});
321	
322						correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
323					}
324				}
325	
326				correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
327				this.logger.debug('Found correlated root categories', {
328					count: correlatedCategoryIds.length,
329					styleIds,
330				});
331	
332				if (correlatedCategoryIds.length === 0) {
333					this.logger.warn('No root category correlations found, using fallback', {
334						styleIds,
335					});
336					correlatedCategoryIds = await this.stylesService.getMostPopularRootCategories({
337						limit: 4,
338					});
339					fallbackUsed = true;
340				}
341	
342				const allPopularStyles =
343					await this.stylesService.getMostPopularStylesByRootCategories({
344						categoryIds: correlatedCategoryIds,
345						limit: 5,
346						excludeIds: [...styleIds, ...exclude],
347					});
348				const allPopularStylesIds = allPopularStyles.map((_style) => _style.style_id);
349	
350				const currentStyleColor = await this.getCurrentColorStyle(styleIds[0]);
351				const products = await this.productHydrationService.hydrateProducts({
352					styleIds: allPopularStylesIds,
353					currentStyleColor,
354				});
355	
356				const productsByStyleId = new Map(products.map((p) => [p.style_id, p]));
357				const activeStyleIds = new Set(products.map((p) => p.style_id));
358	
359				const filteredAllPopularStyles = allPopularStyles.filter((s) =>
360					activeStyleIds.has(s.style_id),
361				);
362	
363				const selectedStyleIds = this.selectRandomStylesFromRootCategories(
364					filteredAllPopularStyles,
365					correlatedCategoryIds,
366				);
367	
368				const selectedStyles = allPopularStyles.filter((style) =>
369					selectedStyleIds.includes(style.style_id),
370				);
371				const sortedStyles = selectedStyles
372					.sort((a, b) => b.purchases_count - a.purchases_count)
373					.slice(0, 4);
374				const finalStyleIds = sortedStyles.map((style) => style.style_id);
375	
376				if (finalStyleIds.length === 0) {
377					this.logger.warn('No style IDs selected for root category recommendations', {
378						styleIds,
379					});
380					return {
381						style_ids: styleIds,
382						frequently_bought_together: [],
383						fallback_used: fallbackUsed,
384					};
385				}
386	
387				this.logger.debug('Selected styles for root category recommendations', {
388					count: finalStyleIds.length,
389				});
390	
391				const finalProducts = finalStyleIds
392					.map((id) => productsByStyleId.get(id))
393					.filter((p): p is IRelatedProduct => p !== undefined);
394	
395				return {
396					style_ids: styleIds,
397					frequently_bought_together: finalProducts,
398					fallback_used: fallbackUsed,
399				};
400			} catch (error) {
401				this.logger.error(
402					`Error getting frequently bought together by root categories for styles ${styleIds.join(', ')}: ${(error as Error).message}`,
403					(error as Error).stack,
404				);
405				throw error;
406			}
407		}
