61				styleIds,
62				excludeCount: exclude.length,
63			});
64	
65			try {
66				const styles = await Promise.all(
67					styleIds.map((id) => this.stylesService.getStyleById({ styleId: id })),
68				);
69	
70				const validStyles = styles.filter(Boolean) as IStyleBase[];
71				if (validStyles.length === 0) {
72					throw new BadRequestException(
73						`No styles found for styleIds: ${styleIds.join(', ')}`,
74					);
75				}
76	
77				this.logger.debug('[getFrequentlyBoughtTogether] Valid styles found', {
78					validCount: validStyles.length,
79					inputCount: styleIds.length,
80				});
81	
82				const cartCategoryIds = validStyles
83					.map((_style) => _style.primary_category_id)
84					.filter((id): id is number => id !== null && id !== undefined);
85				let correlatedCategoryIds: number[] = [];
86	
87				for (const style of validStyles) {
88					if (style.primary_category_id) {
89						const correlations =
90							await this.categoryCorrelationsService.getTopCorrelatedCategories({
91								primaryCategoryId: style.primary_category_id,
92								limit: 4,
93								exclude: cartCategoryIds,
94							});
95	
96						correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
97					}
98				}
99	
100				correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
101				this.logger.debug('Found correlated categories', {
102					count: correlatedCategoryIds.length,
103					styleIds,
104				});
105	
106				if (correlatedCategoryIds.length === 0) {
107					this.logger.warn('No correlations found, using fallback', { styleIds });
108					correlatedCategoryIds = await this.stylesService.getMostPopularCategories({
109						limit: 4,
110					});
111					fallbackUsed = true;
112				}
113	
114				this.logger.log(
115					'[getFrequentlyBoughtTogether] Fetching popular styles from correlated categories',
116					{
