118					},
119				);
120				const allPopularStyles = await this.stylesService.getMostPopularStylesByCategories({
121					categoryIds: correlatedCategoryIds,
122					limit: 5,
123					excludeIds: [...styleIds, ...exclude],
124				});
125				const allPopularStylesIds = allPopularStyles.map((_style) => _style.style_id);
126				this.logger.log('[getFrequentlyBoughtTogether] Popular styles fetched', {
127					count: allPopularStylesIds.length,
128				});
129	
130				const currentStyleColor = await this.getCurrentColorStyle(styleIds[0]);
131				const products = await this.productHydrationService.hydrateProducts({
132					styleIds: allPopularStylesIds,
133					currentStyleColor,
134				});
135				this.logger.log('[getFrequentlyBoughtTogether] Products hydrated', {
136					hydratedCount: products.length,
137				});
138	
139				const productsByStyleId = new Map(products.map((p) => [p.style_id, p]));
140				const activeStyleIds = new Set(products.map((p) => p.style_id));
141	
142				const filteredAllPopularStyles = allPopularStyles.filter((s) =>
143					activeStyleIds.has(s.style_id),
144				);
145	
146				const stylesWithCategory = filteredAllPopularStyles.filter(
147					(style): style is IStyleBase & { primary_category_id: number } =>
148						style.primary_category_id !== null,
149				);
150				const selectedStyleIds = this.selectRandomStylesFromCategories(
151					stylesWithCategory,
152					correlatedCategoryIds,
153				);
154	
155				const selectedStyles = allPopularStyles.filter((style) =>
156					selectedStyleIds.includes(style.style_id),
157				);
158				const sortedStyles = selectedStyles
159					.sort((a, b) => b.purchases_count - a.purchases_count)
160					.slice(0, 4);
161				const finalStyleIds = sortedStyles.map((style) => style.style_id);
162	
163				let finalProducts = finalStyleIds
164					.map((id) => productsByStyleId.get(id))
165					.filter((p): p is IRelatedProduct => p !== undefined);
166	
167				if (finalStyleIds.length < 4) {
168					this.logger.debug('Using fallback for additional recommendations', {
169						currentCount: finalStyleIds.length,
170						targetCount: 4,
171					});
172	
173					const regularResult = await this.getFrequentlyBoughtTogetherByRootCategories({
174						styleIds,
