176					});
177	
178					const additionalProducts = regularResult.frequently_bought_together
179						.filter((product) => !finalStyleIds.includes(product.style_id))
180						.slice(0, 4 - finalStyleIds.length);
181	
182					finalProducts = finalProducts.concat(additionalProducts);
183	
184					this.logger.debug('Added additional recommendations', {
185						count: additionalProducts.length,
186					});
187				}
188	
189				this.logger.debug('Selected styles for recommendations', {
190					count: finalProducts.length,
191				});
192	
193				return {
194					style_ids: styleIds,
195					frequently_bought_together: finalProducts,
196					fallback_used: fallbackUsed,
197				};
198			} catch (error) {
199				this.logger.error(
