import { FrequentlyBoughtTogetherV2QueryDto } from '@dto/frequently-bought-together/frequently-bought-together-v2-query.dto';
import { FrequentlyBoughtTogetherV2ResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-v2-response.dto';

@Injectable()
export class FrequentlyBoughtTogetherService {
	private readonly logger = new Logger(FrequentlyBoughtTogetherService.name);

	constructor(
		private readonly stylesService: StylesService,
		private readonly styleColorsService: StyleColorsService,
		private readonly categoryCorrelationsService: CategoryCorrelationsService,
		private readonly rootCategoriesCorrelationsService: RootCategoriesCorrelationsService,
		private readonly productHydrationService: ProductHydrationService,
		private readonly styleCopurchasesService: StyleCopurchasesService,
		private readonly stylesMvService: StylesMvService,
	) {}

	private async getCurrentColorStyle({
		styleId,
	}: {
		styleId?: number;
	}): Promise<IStyleColorBase | null> {
		if (!styleId) {
			return null;
		}

		const currentStyle = await this.styleColorsService.getStyleByStyleId({
			styleId: Number(styleId),
		});

		if (!currentStyle) {
			this.logger.warn('No style found', { styleId });
		}

		return currentStyle;
	}

	async getFrequentlyBoughtTogether({
		styleIds,
		exclude = [],
	}: FrequentlyBoughtTogetherQueryDto): Promise<FrequentlyBoughtTogetherResponseDto> {
		let fallbackUsed = false;

		this.logger.debug('[getFrequentlyBoughtTogether] Starting FBT fetch', {
			styleIds,
			excludeCount: exclude.length,
		});

		try {
			const styles = await Promise.all(
				styleIds.map((id) => this.stylesService.getStyleById({ styleId: id })),
			);

			const validStyles = styles.filter(Boolean) as IStyleBase[];
			if (validStyles.length === 0) {
				throw new BadRequestException(
					`No styles found for styleIds: ${styleIds.join(', ')}`,
				);
			}

			this.logger.debug('[getFrequentlyBoughtTogether] Valid styles found', {
				validCount: validStyles.length,
				inputCount: styleIds.length,
			});

			const cartCategoryIds = validStyles
				.map((_style) => _style.primary_category_id)
				.filter((id): id is number => id !== null);
			let correlatedCategoryIds: number[] = [];

			for (const style of validStyles) {
				if (style.primary_category_id) {
					const correlations =
						await this.categoryCorrelationsService.getTopCorrelatedCategories({
							primaryCategoryId: style.primary_category_id,
							limit: 4,
							exclude: cartCategoryIds,
						});

					correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
				}
			}

			correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
			this.logger.debug('Found correlated categories', {
				count: correlatedCategoryIds.length,
				styleIds,
			});

			if (correlatedCategoryIds.length === 0) {
				this.logger.warn('No correlations found, using fallback', { styleIds });
				correlatedCategoryIds = await this.stylesService.getMostPopularCategories({
					limit: 4,
				});
				fallbackUsed = true;
			}

			this.logger.log(
				'[getFrequentlyBoughtTogether] Fetching popular styles from correlated categories',
				{
					correlatedCategoryIds,
				},
			);
			const allPopularStyles = await this.stylesService.getMostPopularStylesByCategories({
				categoryIds: correlatedCategoryIds,
				limit: 5,
				excludeIds: [...styleIds, ...exclude],
			});
			const allPopularStylesIds = allPopularStyles.map((_style) => _style.style_id);
			this.logger.log('[getFrequentlyBoughtTogether] Popular styles fetched', {
				count: allPopularStylesIds.length,
			});

			const currentStyleColor = await this.getCurrentColorStyle({
				styleId: styleIds[0],
			});
			const products = await this.productHydrationService.hydrateProducts({
				styleIds: allPopularStylesIds,
				currentStyleColor,
			});
			this.logger.log('[getFrequentlyBoughtTogether] Products hydrated', {
				hydratedCount: products.length,
			});

			const productsByStyleId = new Map(products.map((p) => [p.style_id, p]));
			const activeStyleIds = new Set(products.map((p) => p.style_id));

			const filteredAllPopularStyles = allPopularStyles.filter((s) =>
				activeStyleIds.has(s.style_id),
			);

			const stylesWithCategory = filteredAllPopularStyles.filter(
				(style): style is IStyleBase & { primary_category_id: number } =>
					style.primary_category_id !== null,
			);
			const selectedStyleIds = this.selectRandomStylesFromCategories({
				styles: stylesWithCategory,
				categoryIds: correlatedCategoryIds,
			});

			const selectedStyles = allPopularStyles.filter((style) =>
				selectedStyleIds.includes(style.style_id),
			);
			const sortedStyles = selectedStyles
				.sort((a, b) => b.purchases_count - a.purchases_count)
				.slice(0, 4);
			const finalStyleIds = sortedStyles.map((style) => style.style_id);

			let finalProducts = finalStyleIds
				.map((id) => productsByStyleId.get(id))
				.filter((p): p is IRelatedProduct => p !== undefined);

			if (finalStyleIds.length < 4) {
				this.logger.debug('Using fallback for additional recommendations', {
					currentCount: finalStyleIds.length,
					targetCount: 4,
				});

				const regularResult = await this.getFrequentlyBoughtTogetherByRootCategories({
					styleIds,
					exclude: finalStyleIds.concat(exclude),
				});

				const additionalProducts = regularResult.frequently_bought_together
					.filter((product) => !finalStyleIds.includes(product.style_id))
					.slice(0, 4 - finalStyleIds.length);

				finalProducts = finalProducts.concat(additionalProducts);

				this.logger.debug('Added additional recommendations', {
					count: additionalProducts.length,
				});
			}

			this.logger.debug('Selected styles for recommendations', {
				count: finalProducts.length,
			});

			return {
				style_ids: styleIds,
				frequently_bought_together: finalProducts,
				fallback_used: fallbackUsed,
			};
		} catch (error) {
			this.logger.error(
				`Error getting frequently bought together for styles ${styleIds.join(', ')}: ${(error as Error).message}`,
				(error as Error).stack,
			);
			throw error;
		}
	}

	private selectRandomStylesFromCategories({
		styles,
		categoryIds,
	}: {
		styles: { primary_category_id?: number; style_id: number }[];
		categoryIds: number[];
	}): number[] {
		return this.selectRandomStylesFromCategoriesGeneric({
			styles,
			categoryIds,
			categoryKey: 'primary_category_id',
			categoryLabel: 'Category',
		});
	}

	private selectRandomStylesFromRootCategories({
		styles,
		categoryIds,
	}: {
		styles: { root_category_id?: number; style_id: number }[];
		categoryIds: number[];
	}): number[] {
		return this.selectRandomStylesFromCategoriesGeneric({
			styles,
			categoryIds,
			categoryKey: 'root_category_id',
			categoryLabel: 'Root category',
		});
	}

	private selectRandomStylesFromCategoriesGeneric<K extends string>({
		styles,
		categoryIds,
		categoryKey,
		categoryLabel,
	}: {
		styles: ({ style_id: number } & Partial<Record<K, number>>)[];
		categoryIds: number[];
		categoryKey: K;
		categoryLabel: string;
	}): number[] {
		if (categoryIds.length === 0) {
			return [];
		}

		const stylesByCategory: Record<number, (typeof styles)[number][]> = {};
		for (const style of styles) {
			const categoryId = style[categoryKey];
			if (categoryId !== undefined) {
				// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
				stylesByCategory[categoryId] ??= [];
				stylesByCategory[categoryId].push(style);
			}
		}

		const selectedStyles: number[] = [];

		const emptyCategoryIds: number[] = [];

		for (const categoryId of categoryIds) {
			const categoryStyles = stylesByCategory[categoryId];
			if (categoryStyles && categoryStyles.length > 0) {
				const randomIndex = Math.floor(Math.random() * categoryStyles.length);
				const styleId = categoryStyles[randomIndex]?.style_id;
				if (styleId) {
					selectedStyles.push(styleId);
				}
			} else {
				emptyCategoryIds.push(categoryId);
			}
		}

		if (emptyCategoryIds.length > 0) {
			this.logger.warn(`No styles found for ${categoryLabel.toLowerCase()}`, {
				emptyCategoryIds,
				totalCategories: categoryIds.length,
			});
		}

		this.logger.debug(`${categoryLabel} selection complete`, {
			selectedCount: selectedStyles.length,
			totalCategories: categoryIds.length,
			emptyCategories: emptyCategoryIds.length,
		});

		return selectedStyles;
	}

	async getFrequentlyBoughtTogetherByRootCategories({
		styleIds,
		exclude = [],
	}: FrequentlyBoughtTogetherRootCategoriesQueryDto): Promise<FrequentlyBoughtTogetherRootCategoriesResponseDto> {
		let fallbackUsed = false;

		this.logger.log(
			'[getFrequentlyBoughtTogetherByRootCategories] Starting root category FBT fetch',
			{
				styleIds,
				excludeCount: exclude.length,
			},
		);

		try {
			const styles = await Promise.all(
				styleIds.map((id) => this.stylesService.getStyleById({ styleId: id })),
			);

			const validStyles = styles.filter(Boolean) as IStyleBase[];
			if (validStyles.length === 0) {
				throw new BadRequestException(
					`No styles found for styleIds: ${styleIds.join(', ')}`,
				);
			}

			const cartRootCategoryIds = validStyles
				.map((_style) => _style.root_category_id)
				.filter(Boolean) as number[];
			let correlatedCategoryIds: number[] = [];

			for (const style of validStyles) {
				if (style.root_category_id) {
					const correlations =
						await this.rootCategoriesCorrelationsService.getTopCorrelatedCategories({
							rootCategoryId: style.root_category_id,
							limit: 4,
							exclude: cartRootCategoryIds,
						});

					correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
				}
			}

			correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
			this.logger.debug('Found correlated root categories', {
				count: correlatedCategoryIds.length,
				styleIds,
			});

			if (correlatedCategoryIds.length === 0) {
				this.logger.warn('No root category correlations found, using fallback', {
					styleIds,
				});
				correlatedCategoryIds = await this.stylesService.getMostPopularRootCategories({
					limit: 4,
				});
				fallbackUsed = true;
			}

			const allPopularStyles =
				await this.stylesService.getMostPopularStylesByRootCategories({
					categoryIds: correlatedCategoryIds,
					limit: 5,
					excludeIds: [...styleIds, ...exclude],
				});
			const allPopularStylesIds = allPopularStyles.map((_style) => _style.style_id);

			const currentStyleColor = await this.getCurrentColorStyle({
				styleId: styleIds[0],
			});
			const products = await this.productHydrationService.hydrateProducts({
				styleIds: allPopularStylesIds,
				currentStyleColor,
			});

			const productsByStyleId = new Map(products.map((p) => [p.style_id, p]));
			const activeStyleIds = new Set(products.map((p) => p.style_id));

			const filteredAllPopularStyles = allPopularStyles.filter((s) =>
				activeStyleIds.has(s.style_id),
			);

			const selectedStyleIds = this.selectRandomStylesFromRootCategories({
				styles: filteredAllPopularStyles,
				categoryIds: correlatedCategoryIds,
			});

			const selectedStyles = allPopularStyles.filter((style) =>
				selectedStyleIds.includes(style.style_id),
			);
			const sortedStyles = selectedStyles
				.sort((a, b) => b.purchases_count - a.purchases_count)
				.slice(0, 4);
			const finalStyleIds = sortedStyles.map((style) => style.style_id);

			if (finalStyleIds.length === 0) {
				this.logger.warn('No style IDs selected for root category recommendations', {
					styleIds,
				});
				return {
					style_ids: styleIds,
					frequently_bought_together: [],
					fallback_used: fallbackUsed,
				};
			}

			this.logger.debug('Selected styles for root category recommendations', {
				count: finalStyleIds.length,
			});

			const finalProducts = finalStyleIds
				.map((id) => productsByStyleId.get(id))
				.filter((p): p is IRelatedProduct => p !== undefined);

			return {
				style_ids: styleIds,
				frequently_bought_together: finalProducts,
				fallback_used: fallbackUsed,
			};
		} catch (error) {
			this.logger.error(
				`Error getting frequently bought together by root categories for styles ${styleIds.join(', ')}: ${(error as Error).message}`,
				(error as Error).stack,
			);
			throw error;
		}
	}

	@LogExecution({
		paramFormatter: ([query]: [FrequentlyBoughtTogetherV2QueryDto]) => ({
			styleId: query.styleId,
			colorId: query.colorId,
			excludeCount: query.exclude?.length ?? 0,
			limit: query.limit ?? 4,
			diversifyCategories: query.diversifyCategories,
			favorOppositeType: query.favorOppositeType,
		}),
		responseFormatter: (res: FrequentlyBoughtTogetherV2ResponseDto) => ({
			count: res.frequently_bought_together.length,
			fallbackUsed: res.fallback_used,
		}),
	})
	async getFrequentlyBoughtTogetherV2({
		styleId,
		colorId,
		exclude = [],
		limit = 4,
		diversifyCategories = false,
		favorOppositeType = false,
	}: FrequentlyBoughtTogetherV2QueryDto): Promise<FrequentlyBoughtTogetherV2ResponseDto> {
		try {
			const style = await this.stylesService.getStyleById({ styleId });
			if (!style) {
				throw new BadRequestException(`No style found for styleId: ${styleId}`);
			}

			const useDiversified = diversifyCategories || favorOppositeType;
			let copurchasedStyleIds: number[];

			if (useDiversified) {
				let seedStyleType: string | null = null;
				if (favorOppositeType) {
					const mvStyle = await this.stylesMvService.getByStyleId({ styleId });
					seedStyleType = mvStyle?.style_type ?? null;
				}

				const diversifiedCopurchases =
					await this.styleCopurchasesService.getTopCopurchasesDiversified({
						styleId,
						limit,
						excludeIds: [styleId, ...exclude],
						diversifyCategories,
						favorOppositeType,
						seedStyleType,
					});

				if (diversifiedCopurchases.length === 0) {
					this.logger.debug('No diversified copurchases found, falling back to v1', {
						styleId,
					});
					const v1Result = await this.getFrequentlyBoughtTogether({
						styleIds: [styleId],
						exclude,
					});

					return {
						style_id: styleId,
						frequently_bought_together: v1Result.frequently_bought_together.slice(
							0,
							limit,
						),
						fallback_used: true,
					};
				}

				copurchasedStyleIds = diversifiedCopurchases.map((c) => c.paired_style_id);
			} else {
				const copurchases = await this.styleCopurchasesService.getTopCopurchases({
					styleId,
					limit,
					excludeIds: [styleId, ...exclude],
				});

				if (copurchases.length === 0) {
					this.logger.debug('No copurchases found, falling back to v1', { styleId });
					const v1Result = await this.getFrequentlyBoughtTogether({
						styleIds: [styleId],
						exclude,
					});

					return {
						style_id: styleId,
						frequently_bought_together: v1Result.frequently_bought_together.slice(
							0,
							limit,
						),
						fallback_used: true,
					};
				}

				copurchasedStyleIds = copurchases.map((c) => c.paired_style_id);
			}

			let currentStyleColor: IStyleColorBase | null = null;
			if (colorId) {
				currentStyleColor = await this.styleColorsService.getStyleByStyleAndColorId({
					styleId,
					colorId,
				});
			}
			currentStyleColor ??= await this.getCurrentColorStyle({ styleId });

			const products = await this.productHydrationService.hydrateProducts({
				styleIds: copurchasedStyleIds,
				currentStyleColor,
			});

			this.logger.debug('FBT v2 results', {
				styleId,
				resultCount: products.length,
			});

			return {
				style_id: styleId,
				frequently_bought_together: products,
				fallback_used: false,
			};
		} catch (error) {
			this.logger.error(
				`Error getting FBT v2 for style ${styleId}: ${(error as Error).message}`,
				(error as Error).stack,
			);
			throw error;
		}
	}
}

